parameters.jsonBody:
{
  "contents": [{"parts": [{"text": "Generate SEO-optimized website content for a local business. Business: {{$('Webhook Trigger').item.json.body.business_details.name}}. Category: {{$('Webhook Trigger').item.json.body.business_details.category}}. Location: {{$('Webhook Trigger').item.json.body.business_details.address}}. Services: {{$('Webhook Trigger').item.json.body.business_details.services}}. Generate JSON with: title, meta_description, hero_heading, hero_subheading, about_text, service_descriptions (array of objects with name and description), cta_text, footer_text. All optimized for local SEO in India."}]}],
  "generationConfig": {"temperature": 0.7, "responseMimeType": "application/json"}
}

parameters.jsCode:
const business = $('Webhook Trigger').first().json.body.business_details;
let seoContent;
try {
  const text = $input.first().json.candidates[0].content.parts[0].text;
  seoContent = JSON.parse(text);
} catch (e) {
  seoContent = { title: business.name, meta_description: '', hero_heading: business.name, hero_subheading: 'Welcome', about_text: '', service_descriptions: [], cta_text: 'Contact Us', footer_text: '' };
}

const html = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${seoContent.title}</title><meta name="description" content="${seoContent.meta_description}"><script src="https://cdn.tailwindcss.com"></script><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"></head><body class="font-['Inter'] bg-white text-gray-900"><nav class="bg-white shadow-sm sticky top-0 z-50"><div class="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center"><h1 class="text-xl font-bold">${business.name}</h1><a href="tel:${business.phone || ''}" class="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm">Call Now</a></div></nav><section class="bg-gradient-to-br from-blue-600 to-blue-800 text-white py-20 px-4"><div class="max-w-4xl mx-auto text-center"><h2 class="text-4xl md:text-5xl font-bold mb-4">${seoContent.hero_heading}</h2><p class="text-lg opacity-90 mb-8">${seoContent.hero_subheading}</p><a href="tel:${business.phone || ''}" class="bg-white text-blue-600 px-8 py-3 rounded-lg font-semibold text-lg">${seoContent.cta_text}</a></div></section><section class="py-16 px-4"><div class="max-w-4xl mx-auto"><h3 class="text-3xl font-bold mb-6">About Us</h3><p class="text-gray-600 text-lg leading-relaxed">${seoContent.about_text}</p></div></section><footer class="bg-gray-900 text-gray-400 py-8 px-4 text-center"><p>${seoContent.footer_text}</p><p class="text-xs mt-2">Made with Seriousprenuer</p></footer></body></html>`;

return [{ json: { html, seoContent, business } }];
